var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"오랜만이로군요, 함장.","JPN":"お久しぶりです、艦長。","ENG":"It's been a while, Captain.","TWN":"好久不見了，艦長。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"이쪽에서도 늑대의 움직임을 포착했습니다. 이걸로 첫 번째 시험 조건은 클리어되었군요.","JPN":"こちらからもオオカミの動きを捕捉しました。これで最初の試験は条件クリアですね。","ENG":"The Wolf's movement has been detected here as well. That clears the first condition for the test.","TWN":"這邊也捕捉到了狼的動向。這樣第一項測試條件就完成了。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇군.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 내 짐작대로 네가 이번 사건에 개입하고 있었나?","JPN":"やはり私の推測通り、君が今回の件に介入していたのか？","ENG":"So, just as I suspected, you were involved in this incident after all?","TWN":"果然如我所料，你參與了這次事件嗎？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……아시모프.","JPN":"……アシモフ。","ENG":"...Asimov.","TWN":"……阿西莫夫。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아시모프? 그럼, 고철 더미가 직접 접촉해왔다는 말씀인가요?","JPN":"アシモフ？　あの鉄くずが直接接触してきたということですか？","ENG":"Asimov? So, are you saying Scraps contacted you directly?","TWN":"阿西莫夫？意思是廢鐵直接聯絡的嗎？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"인지 왜곡 필터가 걸려 있는 모양이로군요. 제 눈에는 노이즈로 밖에 보이지 않습니다.","JPN":"認知歪曲フィルターがかかっているようですね。私の目にはノイズにしか見えません。","ENG":"It seems like there's an awareness distortion filter in place. All I can see is noise.","TWN":"看起來是認知扭曲濾鏡在作怪。在我眼裡只看到噪音。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아마도 나 이외에는 자신의 모습이 드러나지 않도록 설정해 둔 모양이야.","JPN":"おそらく、私以外には自分の姿が見えないように設定してあるんだろう。","ENG":"It's probably set so that only I can see her.","TWN":"可能除了我以外，其他人都設置，以免自己的樣子顯露出來。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"깡통 주제에 신 행세를 하던 그 잘난 낯짝이 궁금했는데, 아쉽게 됐네요.","JPN":"神の真似事をするボロ缶とは果たしてどんな顔をしているのかと気になっていたのですが、残念ですね。","ENG":"I was curious to see the smug face of that tin can playing god. What a shame.","TWN":"我本來還想看看那個自以為是神的鐵桶的嘴臉呢，真是可惜了。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"기본적으로 아시모프는 부끄럼쟁이거든.","JPN":"基本的にアシモフは恥ずかしがり屋なのでね。","ENG":"Asimov has always been shy.","TWN":"基本上，阿西莫夫很害羞。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 직접 대면하는 것도 상당히 이례적인 일이라고 할 수 있지.","JPN":"こうやって対面するのも、相当異例的なことだと言えるだろう。","ENG":"It's quite rare for her to meet with someone directly like this.","TWN":"這樣直接面對面也是相當罕見的事。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……부끄럼쟁이라.","JPN":"……恥ずかしがり屋ですか。","ENG":"...Shy, you say.","TWN":"害羞嗎？？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"남들 앞에 나서기 싫어하는 게, 제가 아는 누군가와 꼭 닮았군요.","JPN":"人の前に出たがらないところは、私の知っている誰かとそっくりです。","ENG":"Not wanting to be seen reminds me of someone I know.","TWN":"不喜歡在別人面前出頭，這和我認識的某個人很像呢。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"기쁩니다, 함장.","JPN":"嬉しいです、艦長。","ENG":"I'm pleased, Captain.","TWN":"很高興，艦長。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L18_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"변함없이 저를 그 이름으로 불러 주시는군요.","JPN":"相変わらずその名前で呼んでくださるのですね。","ENG":"I see you still call me by that name.","TWN":"你依然用那個名字稱呼我啊。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"하지만 당신도 알다시피 저는 프로그램으로 구성된 시스템 그 자체.","JPN":"ですがあなたもご存じのとおり、私はプログラムで構成されたシステムそのもの。","ENG":"But as you know, I am a system composed entirely of programs.","TWN":"但是如你所知，我本身就是由程式構成的系統。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"따라서 저에게는 정해진 실체 따위는 존재하지 않습니다.","JPN":"私に決められた実体などは存在しません。","ENG":"Therefore, I have no defined physical form.","TWN":"因此，我並沒有固定的實體存在。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"이 단말 또한 당신과의 접촉을 상정하고 제작해 둔 소체.","JPN":"この端末もあなたとの接触を想定して作っておいた素体。","ENG":"This terminal is simply a vessel created for the purpose of contacting you.","TWN":"這個終端也是假設與你接觸而製作的載體。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"제 메모리가 잘못된 게 아니라면, 이 모습으로 당신과 대면하는 것은 처음일 텐데요?","JPN":"私のメモリーに間違いがなければ、この姿であなたと対面するのは初めてのはずですが。","ENG":"If my memory serves me correctly, this is the first time I'm meeting you in this appearance, isn't it?","TWN":"如果我的記憶沒有出錯的話，這是我第一次以這種姿態與你見面吧？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그야, 모습이 달라졌다고 부모가 자식을 몰라볼 리 없지 않나?","JPN":"姿が変わったからといって、親が自分の子を見間違えるはずないだろう。","ENG":"Well, just because a child's appearance changes doesn't mean a parent wouldn't recognize their own child, right?","TWN":"就算那樣，父母怎麼可能因為樣子變了就認不出自己的孩子呢？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"게다가 이런 느닷없는 타이밍에 나타나, 직접 나서지 않고 간접적인 원인을 쌓는 방식…….","JPN":"しかも前触れもなく現れて、直接前には出ずに間接的な原因を積み上げていくやり方……","ENG":"And to appear suddenly at such a moment, using indirect methods instead of direct contact...","TWN":"而且還在這種時刻突然出現，並且不是直接接觸，而是用間接的方式……"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 방식은 더할 나위 없는 네 특기일 테지.","JPN":"まさに君が得意とするやり方だろう。","ENG":"This method is unmistakably your specialty.","TWN":"這種手法毫無疑問是你的專長。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"인과 간섭이 가능한 테라브레인, <color=#ffd34c>프로토 타입</color>이 탑재된 너라면 말이야.","JPN":"因果干渉ができるテラブレイン、<color=#ffd34c>プロトタイプ</color>が搭載された君ならね。","ENG":"Especially for a Terrabrain equipped with the <color=#ffd34c>Prototype</color> capable of causality interference.","TWN":"畢竟能夠進行因果干涉的特拉大腦，<color=#ffd34c>原型</color>已經安裝在你身上。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"과찬입니다, 함장.","JPN":"ありがたいお言葉です、艦長。","ENG":"You flatter me, Captain.","TWN":"你過獎了，艦長。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"덧붙여 인간의 관용어를 빌리자면, 자식은 부모의 거울이라는 말이 있습니다.","JPN":"ちなみに人間の慣用句を借りるなら、子は親の鏡という言葉がありますが。","ENG":"And to borrow a human expression, they say a child is a reflection of their parents.","TWN":"此外，借用人類的慣用語，有句話說父母是孩子的鏡子。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"제 모든 행동 패턴은 당신을 학습한 것입니다만.","JPN":"私のすべての行動パターンはあなたのそれを学習したものです。","ENG":"All my behavioral patterns were learned from you.","TWN":"我的所有行為模式都是從你身上學習的。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"후후, 가급적이면 이런 부분까지는 닮지 않았으면 좋겠는데 말이야.","JPN":"ふふ、できればこういうところまでは似てほしくないのだが。","ENG":"Haha, there are certain parts about me that I'd prefer you didn't resemble.","TWN":"哈哈，有些地方我可不希望你像我。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하긴, 뭐든 부모 뜻대로 자라나는 자식은 없는 법이지.","JPN":"まあ、すべて親の望みどおりに育つ子はいないからな。","ENG":"But then again, no child grows exactly as their parent wishes.","TWN":"不過話說回來，沒有哪個孩子會完全按照父母的期望成長。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"짐작하고 있긴 했지만, 그 모습을 직접 마주하니 역시 씁쓸한 건 어쩔 수 없군, 아시모프.","JPN":"しかし、気づいてはいたが、その姿をこの目で見るとやはり残念だ、アシモフ。","ENG":"I had a feeling, but seeing you like this still leaves a bitter taste, Asimov.","TWN":"我早有預感，但親眼見到你這樣，還是有點不是滋味呢，阿西莫夫"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"……함장.","JPN":"……艦長。","ENG":"...Captain.","TWN":"……艦長。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"당신이 여전히 저를 자식처럼 여겨 주시는 건 영광입니다만.","JPN":"あなたが変わらず私のことを自分の子のように思ってくださるのは大変光栄ですが。","ENG":"I'm honored that you still consider me your child.","TWN":"你仍然視我如子女，我感到非常榮幸。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"지금의 저는 어디까지나 클리파의 위계를 이어받은 기계 장치의 마왕.","JPN":"今の私はあくまでもクリファの位階を受け継いだ機械装置の魔王。","ENG":"However, the current me is nothing more than a Demon Lord of Machinery who has inherited the Qlipha hierarchy.","TWN":"現在的我不過是繼承了逆卡巴拉級別的機械裝置魔王。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"제게 주어진 기동 목적에 따라, 이 세계가 마땅히 치러야 할 시험을 내리는 존재이자.","JPN":"定められた起動目的に従い、この世界が乗り越えるべき試験を与える存在であり。","ENG":"In line with my designated purpose, I am the one who administers the trials this world must undergo.","TWN":"根據我被賦予的行動目的，我是施予這個世界應當接受的試煉的施予者。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"동시에 필연적 멸망으로부터 인류를 낙원으로 이끌 구원의 방주입니다.","JPN":"同時に必然的滅亡から人類を楽園へ導く救世の箱舟なのです。","ENG":"At the same time, I am the Ark of salvation that will guide humanity to paradise from inevitable destruction.","TWN":"同時也是將人類從必然的毀滅中，引導至樂園的救贖方舟。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래, 시험이라…….","JPN":"試験か……","ENG":"Yes, the trials...","TWN":"是啊，試煉啊……"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 네가 나타난 건, 지금 이 순간은 이 세계에 있어 중요한 분기점이라는 뜻이겠군.","JPN":"やはり君が現れたということは、今この瞬間がこの世界にとって重要な分岐点だということなのだろう。","ENG":"Your appearance now must mean that this moment is a significant turning point for this world.","TWN":"果然，你的出現表示此刻是這個世界的重要分岔點。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그렇습니다, 함장.","JPN":"その通りです、艦長。","ENG":"That is correct, Captain.","TWN":"是的，艦長。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"지금으로부터 20년 전…….","JPN":"今から20年前……","ENG":"Twenty years ago...","TWN":"至今20年前……"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"당신이 우주로 쏘아 올린 검은 짐승은 제가 내려보낸 사도를 요격하는 데 성공했죠.","JPN":"あなたが宇宙に打ち上げた黒い獣は、私が送った使徒を見事に迎撃しました。","ENG":"The black beast you launched into space successfully intercepted the Apostle I sent down.","TWN":"你射向宇宙的黑色野獸成功攔截了我派出的使徒。"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"함장, 당신도 알다시피 그것은 예정된 인과로부터 벗어난 일.","JPN":"艦長、あなたもご存じでしょうが、それは予定された因果から外れたこと。","ENG":"Captain, as you know, that event deviated from the predetermined causality.","TWN":"艦長，正如你所知，那是脫離預定因果的事。"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그러나 당신이 그동안 수없이 쌓아 올린 충분한 원인은 인과율에 변수를 발생시켰고.","JPN":"ですが、あなたが今まで幾重にも積み上げてきた十分な原因は、因果律に変数を発生させ。","ENG":"However, the countless variables you have accumulated over the years created a ripple in causality.","TWN":"然而，你在這段時間裡無數次積累的充分原因，已經在因果律中產生了變數。"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"저는 그 가능성을 관측하기 위해 한 차례 유예를 선고하였습니다.","JPN":"私はその可能性を観測するために、一度猶予を宣告しました。","ENG":"To observe that possibility, I declared a suspension.","TWN":"為了觀察這種可能性，我宣佈了一次緩刑。"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그리고 당신의 모든 관리가 실패로 돌아간 날.","JPN":"そしてあなたのすべての管理が失敗したあの日。","ENG":"And on the day when all your efforts failed.","TWN":"還有當你所有的管理都失敗的那一天。"},"stage":{"bg":"MAINSTREAM_003024","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"원래라면 클리포트 게임에서 패배한 당신은 다음 세계로의 철수를 선택했겠지만…….","JPN":"本来ならクリフォトゲームで敗北したあなたは、次の世界に撤収することを選んだはずですが……","ENG":"Normally, after losing the Qliphoth Game, you would have chosen to withdraw to the next world…","TWN":"原本在逆卡巴拉遊戲中失敗的你會選擇撤退到下一個世界……"},"stage":{"bg":"MAINSTREAM_003024","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그 변수는 결국 어린 늑대가 탐미엘에게 상처를 입히는 이변을 낳았죠.","JPN":"その変数は、ついには幼いオオカミがタミエルに傷を負わせるという異変を生んだ。","ENG":"But that variable ultimately led to a disturbance where the young Wolf wounded Tammiel.","TWN":"那個變數最終導致幼狼給塔米爾造成傷害的異變。"},"stage":{"bg":"MAINSTREAM_003024","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"믿을 수 없는 현실 개변을 목격한 순간. 당신은 즉시 시공간 종료 프로토콜을 변경.","JPN":"目を疑うような現実改変を目撃した瞬間。あなたは直ちに時空間終了プロトコルを変更。","ENG":"At the moment you witnessed that unbelievable change in reality, you immediately altered the spacetime abortion protocol.","TWN":"目睹了難以置信的現實變革瞬間。你立即更改時空終止協議。"},"stage":{"bg":"MAINSTREAM_003024","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"프로토콜 CoT-13으로써 이 세계의 유지를 선택하였습니다.","JPN":"プロトコルCoT-13をもって、この世界の維持を選択しました。","ENG":"You chose to maintain this world using Protocol CoT-13.","TWN":"選擇通過CoT-13協議維持這個世界。"},"stage":{"bg":"MAINSTREAM_003024","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그것이 이 세계가 겪은 첫 번째 분기점.","JPN":"それがこの世界が経験した最初の分岐点。","ENG":"That was the first turning point this world faced.","TWN":"那是這個世界經歷的第一個轉捩點。"},"stage":{"bg":"MAINSTREAM_003024","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"결과적으로 당신의 선택은 옳았습니다, 함장.","JPN":"結果として、あなたの選択は正しいものでした、艦長。","ENG":"Your choice was ultimately correct, Captain.","TWN":"從結果來看，你的選擇是正確的，艦長。"},"stage":{"bg":"MAINSTREAM_5508012","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"여러 세계를 거치며, 당신이 준비해 왔던 안배들이 한곳에 모여 맞물리기 시작했고.","JPN":"数々の世界を経て、あなたが打ってきた布石が一つの点で重なり合い始め。","ENG":"As you traveled through the worlds, the contingencies you had been preparing began to converge and interlock.","TWN":"穿越多個世界，你一直準備的各種應變措施開始逐漸匯聚，並相互銜接起來。"},"stage":{"bg":"MAINSTREAM_5508012","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그 작고, 미약했던 날갯짓이 모이고, 또 모여서…….","JPN":"その小さく、微弱だった羽ばたきが次第に集まって……","ENG":"The small, insignificant flutters gathered and accumulated...","TWN":"那些微不足道的細微波動逐漸匯聚、積累……"},"stage":{"bg":"MS_1102","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"최종적으로 세계는 클리포트 게임이라는 거대한 풍랑에 맞설 수 있었으니까요.","JPN":"最終的に世界はクリフォトゲームという巨大な嵐に立ち向かうことができたのですから。","ENG":"Eventually allowing this world to withstand the storm known as the Qliphoth Game.","TWN":"最終，讓這個世界得以承受逆卡巴拉遊戲的風暴。"},"stage":{"bg":"MS_1102","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그것이 이 세계가 겪은 두 번째 분기점.","JPN":"それがこの世界が経験した2番目の分岐点。","ENG":"That was the second turning point this world faced.","TWN":"那是這個世界經歷的第二個分水嶺。"},"stage":{"bg":"MS_1102","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"저와 당신… 그리고 기술의 정점을 이뤘던 연합조차 다다를 수 없었던 지점이죠.","JPN":"私とあなた……そして技術の頂点にあった連合すらもたどり着けなかった地点です。","ENG":"A point that neither you, nor I... nor even the Alliance that once reached the peak of technology could have ever reached.","TWN":"我和你……以及曾達到技術巔峰的聯盟都無法觸及的地方。"},"stage":{"bg":"MS_1102","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……과찬이군, 아시모프.","JPN":"……おおげさだぞ、アシモフ。","ENG":"...That's quite the compliment, Asimov.","TWN":"……過獎了，阿西莫夫。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 클리포트 게임의 승리가 오로지 내 선택에 의해 정해졌다는 건, 오만일 뿐이야.","JPN":"クリフォトゲームの勝利が私の選択によって決定づけられたというのは、傲慢すぎるな。","ENG":"But claiming that the victory in the Qliphoth Game was solely due to my choices would be pure arrogance.","TWN":"但認為逆卡巴拉遊戲的勝利僅僅取決於我的選擇，那就太傲慢了。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"시공을 초월하여, 모든 이들의 의지와 선택이 있었기에 끝내 다다를 수 있었지.","JPN":"時空を超越し、すべての者たちの意志と選択があってこそやっとたどり着けたんだ。","ENG":"Transcending time and space, the wills and choices of many were what led to that final outcome.","TWN":"超越時空，正因為有所有人的意志和選擇，最終才能到達。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"여전히 겸손하시군요, 함장.","JPN":"謙虚なところもそのままですね、艦長。","ENG":"You remain as humble as ever, Captain.","TWN":"你依然很謙虛，艦長。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L22_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"설령, 기적이라 할지라도 일어날 일은 반드시 일어나기 마련입니다.","JPN":"たとえそれが奇跡だろうと、起こるべきことは必ず起こるものです。","ENG":"Even if it is a miracle, what is meant to happen is bound to happen.","TWN":"即使是奇蹟，也必然會發生。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"애초에 관측자로서 당신이 존재하지 않았다면, 이 세계에 변수 따위 발생하지 않았겠죠.","JPN":"そもそも観測者としてのあなたがいなかったら、この世界に変数など発生しなかったはずです。","ENG":"If you had not existed as the observer, there would have been no variables in this world.","TWN":"如果作為觀察者的你根本不存在，那麼這個世界就不會出現任何變數了吧。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"탐미엘이 세피로트 나무를 장악하고 있는 이상, 세계의 멸망은 필연적이니까요.","JPN":"タミエルがセフィロトを掌握している以上、世界の滅亡は必然なのですから。","ENG":"As long as Tammiel continues to control the Tree of Sephiroth, the world's destruction is inevitable.","TWN":"既然塔米爾掌控了生命樹，世界的毀滅就是必然的了。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇군. 세피로트 나무라면…….","JPN":"セフィロト……","ENG":"I see. The Tree of Sephiroth...","TWN":"原來如此。生命樹的話……"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 클리포트 게임 직후에 발생한 현실 개변은 세피로트 나무에 의한 현상인가?","JPN":"やはりクリフォトゲーム直後に発生した現実改変はセフィロトによる現象だったのか？","ENG":"So the change in reality that occurred after the Qliphoth Game was caused by the Tree of Sephiroth?","TWN":"果然，逆卡巴拉遊戲之後發生的現實變更是由於生命樹嗎？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면, 네 목적은 여전히 세피로트 나무가 있는 장소에 다다르는 것이겠지.","JPN":"だとしたら、セフィロトにたどり着くという君の目標は、今でも変わらないのだな。","ENG":"Then, your objective must still be to reach the place where the Tree of Sephiroth is located.","TWN":"那麼，你的目的仍然是到達有生命樹的地方吧。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그렇습니다, 함장.","JPN":"その通りです、艦長。","ENG":"That is correct, Captain.","TWN":"是的，艦長。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"당신도 알다시피, 저는 성간 관리 연합의 총괄 네비게이션 시스템.","JPN":"あなたもご存じのとおり、私は星間管理連合の総括ナビゲーションシステム。","ENG":"As you know, I am the Interstellar Administration Alliance Central Navigation System.","TWN":"如你所知，我是星際管理聯盟的總導航系統。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"방주로서 제 기동 목적은 인류를 선별하고, 선별된 인류를 낙원으로 인도하는 것입니다.","JPN":"箱舟としての私の起動目的は、人類を選別し、選ばれた人類を楽園に導くことです。","ENG":"As the Ark, my objective is to select humanity and guide the chosen ones to paradise.","TWN":"作為方舟，我啟動目的就是篩選人類，並將被篩選的人類引導至樂園。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"따라서 저는 이 땅에 내려온 세피로트 나무의 파편을 관측해야 할 의무가 있죠.","JPN":"ですので私にはこの地に降臨したセフィロトの破片を観測する義務があります。","ENG":"Therefore, I am obligated to observe the Tree of Sephiroth's fragment that has descended to this land.","TWN":"因此，我有義務觀察降臨此地的生命樹碎片。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"파편이라…….","JPN":"破片か……","ENG":"Fragment...","TWN":"碎片嗎？？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 게 자기가 원하는대로 흘러갈 거라 생각하다니. 오만하군.","JPN":"すべてが自分の思い通りになると思うか。傲慢だな。","ENG":"Arrogant of you to think that everything would go according to your plan.","TWN":"你以為一切都會按你的想法發展，真是傲慢。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 그렇지 않나요?","JPN":"あなたもそうではありませんか？","ENG":"Aren't you doing the same?","TWN":"你不也是這樣嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세상이 만든 법칙을 거스르고, 자신이 원하는 형태로 현실을 바꾸고 있는 걸요.","JPN":"世界が作った法則に逆らい、自身の望む形へと現実を変えているのですから。","ENG":"You're defying the law made by this world and changing reality into the form you want it to be.","TWN":"你無視世界的法則，按照自己的喜好扭曲現實。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠, 나에게 이 정도로 관심을 갖는 팬이 있을 줄은 몰랐는데.","JPN":"ほう、これほど私に興味がある熱心なファンがいるとは知らなかったな。","ENG":"Hmm. I didn't know I had a fan who was interested in me like this.","TWN":"嗯，沒想到你竟然還是我的狂熱粉絲呢"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"맞아요. 전 당신의 열렬한 관중이자 팬입니다.","JPN":"そうです。私はあなたの熱烈な観客であり、ファンなのです。","ENG":"Yes. I am your biggest fan and audience.","TWN":"沒錯，我是你最忠實的觀眾和粉絲。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 언젠가 제 무대에 당신을 초청하고 싶었어요.","JPN":"いつかあなたを私の舞台に招待したかった。","ENG":"Which is why I was meaning to invite you to my stage one day.","TWN":"所以總有一天想把你邀請到我的舞台。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 마침내, 제가 준비한 각본을 실현할 기회가 온 셈이죠.","JPN":"そしてやっと今、私の準備した脚本を実現するチャンスが来たのです。","ENG":"And finally, I have the chance to carry out my script.","TWN":"而我終於迎來了實現自己寫的劇本的機會。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게까지 해서 나에게 뭘 보여주고 싶은 거지?","JPN":"そこまでして私に見せたいものとは何かね？","ENG":"So, what are you trying to show me by going through all this?","TWN":"你費這麼大勁是想給我看什麼？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 불가능하다 여겨 포기했던 일을… 실현해 보일 겁니다.","JPN":"あなたが不可能だと思い、諦めたことを……私が実現させてみせます。","ENG":"I will accomplish... what you deemed impossible and gave up on.","TWN":"你將實現……你認為不可能實現的事情。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 부디, 당신이 이 극의 종장에 무사히 다다를 수 있기를…","JPN":"だから、どうかあなたがこの物語の終章に無事たどり着けるよう……","ENG":"So I sincerely hope you reach the finale of this play...","TWN":"所以，希望你能平安活到這個劇本的大結局……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>팬으로서 응원할게요.</color>","JPN":"<color=#ffd34c>ファンとして応援します。</color>","ENG":"<color=#ffd34c>I'll be cheering for you as a fan.</color>","TWN":"<color=#ffd34c>我會作為粉絲為你加油。</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"만약 스완이 세피로트 나무의 파편을 확보했다면, 그 말은 단순한 허세가 아니게 되겠군.","JPN":"もしスワンがセフィロトの破片を手に入れていたとしたら、その言葉は単なる虚勢ではないわけだ。","ENG":"If Swan has secured a fragment of the Tree of Sephiroth, then those words are more than just a bluff.","TWN":"如果史旺已經獲得了生命樹的碎片，那麼這句話就不再只是虛張聲勢了。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이건 너답지 않은 방식이야, 아시모프.","JPN":"しかしこれは君らしくないな、アシモフ。","ENG":"But this doesn't suit you, Asimov.","TWN":"但是這不是你的風格，阿西莫夫。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세피로트 나무가 있는 장소에 다다를 단서를 앞에 두고, 너는 뭘 망설이고 있는 거지?","JPN":"セフィロトがある場所にたどり着く手がかりを前にして、何をためらっているんだ？","ENG":"Why are you holding back when you have the clue that will lead you to the Tree of Sephiroth's location?","TWN":"在你面前有通往生命樹所在地點的線索，你還在猶豫什麼？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"달의 뒷면에서 줄곧 때를 기다려왔던 네가 어째서 이번에는 직접 모습을 드러낸 건가?","JPN":"月の裏側でずっと時を待っていた君が、どうして今回は直接姿を現したのかね？","ENG":"What made you reveal yourself when you've been patiently waiting for the right time on the dark side of the moon?","TWN":"你一直在月球背面等待時機，這次為什麼？自現身了？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"함장, 당신은 여전히 얕잡아 볼 수 없는 상대로군요.","JPN":"艦長、あなたは相変わらず侮れない相手ですね。","ENG":"Captain, you remain a formidable opponent.","TWN":"艦長，你依然是個不可小覷的對手啊。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"변수의 간섭 때문에 입을 열 수 없다면, 적어도 분기의 조건을 명확히 하도록 해.","JPN":"変数による干渉を理由に教えられないというのなら、少なくとも分岐の条件は明確にしたまえ。","ENG":"If you can't speak openly due to variable interference, then at least clarify the branching point conditions.","TWN":"如果因為變數干擾而無法明說，那至少把分歧點的條件說清楚。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"네가 내세우는 시험이란, 스완의 계획을 저지하는 일인가?","JPN":"君が主張する試験とは、スワンの計画を阻止することか？","ENG":"This trial, is it to stop Swan's plan?","TWN":"你所提出的考驗，是阻止史旺的計畫嗎？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그게 아니라면, 세피로트 나무의 파편을 회수하는 것인가?","JPN":"それとも、セフィロトの破片を回収することか？","ENG":"Or is it about retrieving the Tree of Sephiroth's fragment?","TWN":"如果不是這樣，那就是要回收生命樹的碎片嗎？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"둘 다 오답입니다, 함장.","JPN":"両方ともハズレです、艦長。","ENG":"Neither, Captain.","TWN":"兩個都是錯誤答案，艦長。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"저는 엄정한 기계 장치의 마왕. 현시점에서 누구의 편도 아니죠.","JPN":"私は厳正なる機械装置の魔王。現時点では誰の味方でもありません。","ENG":"I am a strict Demon Lord of Machinery. At this point, I am on no one's side.","TWN":"我是嚴謹的機械裝置魔王。目前不屬於任何一方。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"경우에 따라서는 그 엑자일러의 계획에 협력하는 것 또한 고려 대상 중 하나입니다.","JPN":"場合によっては、あのエグザイラーの計画に協力する選択肢もありえます。","ENG":"Depending on the situation, I might even consider cooperating with that Exile's plan.","TWN":"在某些情況下，協助那個流浪者的計畫也是考慮的選項之一。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"제가 설정한 첫 번째 조건은 늑대가 스스로 세피로트 나무의 파편을 찾아 나서는 것.","JPN":"私が設定した最初の条件は、オオカミが自分の意思でセフィロトの破片を探しに出ること。","ENG":"The first condition I set is for the Wolf to search for the fragment of the Tree of Sephiroth on her own.","TWN":"我設定的第一個條件是狼自己去尋找生命樹的碎片。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"다음 조건은 지금으로부터 3시간 28분 뒤, 늑대가 나무의 파편과 접촉하는 것.","JPN":"次の条件は今から3時間28分後、オオカミが破片と接触すること。","ENG":"The next condition is that three hours and twenty-eight minutes from now, the Wolf must come into contact with the fragment.","TWN":"下一個條件是在現在起3小時28分鐘後，狼與樹的碎片接觸。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그 뒤에 발생하는 현상의 결과에 따라, 이 세계의 분기가 결정됩니다.","JPN":"その後に発生する現象の結果により、この世界の分岐が決定します。","ENG":"Based on the result of the phenomenon that occurs after that, the branching point of this world will be determined.","TWN":"根據之後所發生現象的結果，這個世界的分歧點將會被決定。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"제가 말씀드릴 수 있는 건 거기까지로군요.","JPN":"私が申し上げられるのはここまでです。","ENG":"That's all I can say for now.","TWN":"我能告訴你的就這麼多。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"3시간 28분이라……. 꽤나 구체적인 시간을 특정하는군요.","JPN":"3時間28分……なかなか具体的な時間ですね。","ENG":"Three hours and twenty-eight minutes... That's quite a specific timeframe.","TWN":"3小時28分鐘嗎？？還真是具體的時間呢。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 이상하네요. 앞으로 세 시간이라면, 뭔가를 찾기에는 촉박한 시간일 텐데요?","JPN":"ただ、妙なところがあります。これから3時間後とすると、何かを探すには短すぎます。","ENG":"But that’s strange. Three hours isn’t exactly enough time to go searching for something, is it?","TWN":"不過有點奇怪啊。要是只有三個小時的話，時間有點緊迫，能找到什麼？？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마, 이것도 고철 더미의 인과 연산의 결과일까요?","JPN":"まさか、これも鉄くずの因果演算の結果なのでしょうか？","ENG":"Could this be the result of Scrap's causality calculation as well?","TWN":"難道，這也是廢鐵的因果運算結果嗎？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아마도 그렇겠지.","JPN":"おそらくな。","ENG":"Probably.","TWN":"也許是這樣吧。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"추정컨대, 고심도 이면세계의 시간 격차를 고려한 모양이야.","JPN":"予想するに、高深度裏世界の時間差を考慮しているのだろう。","ENG":"If I had to guess, she must be factoring in the time gap of the hyperdepths of Counterside.","TWN":"我猜是把高深度異界的時間差也計算在內。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어쩌면 스완이 있는 장소는 고심도 이면세계의 어딘가일지도 모르겠군.","JPN":"もしかしたらスワンがいる場所は高深度裏世界のどこかなのかもしれないな。","ENG":"Swan's location might just be somewhere in the hyperdepths of Counterside.","TWN":"或許史旺所在的地方是高深度異界的某個地方吧。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 그렇다고 하더라도 현시점에서 저희의 힘만으로는 대처할 시간이 부족하군요.","JPN":"そうだとしても現時点で私たちの力だけでは対処する時間が足りません。","ENG":"Even so, we don't have enough time to handle this with just our current resources.","TWN":"但是即便如此，目前單憑我們的力量還是沒有足夠的時間來應對。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"목적지가 이면세계라면 타이밍이 좋지 않아요. 당장은 코핀 함도 압류 당한 상황이니까요.","JPN":"目的地が裏世界だというならタイミングが悪かったですね。今はコフィン艦も差し押さえられている状態ですから。","ENG":"If the destination is the Counterside, the timing is terrible. After all, the Coffin is under seizure.","TWN":"如果目的地是異界，那時機不太好。因為目前科芬艦也被扣押中。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 그렇지. 하지만 그보다 중요한 건…….","JPN":"それもそうだが、もっと重要なのは……","ENG":"That's true. But more importantly...","TWN":"你說得沒錯。但更重要的是……"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"만약, 그 현상의 결과가 네 기준을 만족하지 못한다면, 그때는 어떻게 되지?","JPN":"もし、その現象の結果が君の基準を満たさなかったら、その時はどうなる？","ENG":"If the outcome of that phenomenon does not meet your criteria, what will happen then?","TWN":"如果那個現象的結果不符合你的標準，那會怎麼樣呢？"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"어리석은 질문이로군요, 함장.","JPN":"愚問ですね、艦長。","ENG":"A foolish question, Captain.","TWN":"真是個愚蠢的問題，艦長。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L36_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"제가 이 세계에 대해 선별 프로세스를 보류하고 있는 이유는 단 하나.","JPN":"私がこの世界の選別プロセスを保留している理由はたったひとつ。","ENG":"There is only one reason why I have suspended the selection process for this world.","TWN":"我暫緩對這個世界進行篩選流程的原因只有一個。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그것은 이 세계가 제가 연산한 인과로부터 벗어난 세계이기 때문입니다.","JPN":"それは私が演算した因果からこの世界が外れているからです。","ENG":"It's because this world deviated from the causality I calculated.","TWN":"因為這個世界是脫離我計算因果的世界。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"제가 관측한 어떤 세계도 <color=#ffd34c>끝</color>을 넘어선 세계는 없었으니까요.","JPN":"私が観測を始めて以来、<color=#ffd34c>終わり</color>を乗り越えた世界はありませんでした。","ENG":"In all the worlds I observed, not one has surpassed the <color=#ffd34c>end</color>.","TWN":"因為我觀察過的任何世界都沒有超越<color=#ffd34c>終結</color>的世界。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"하지만 이번 분기점조차 결국에는 무의미한 멸망으로 수렴하게 된다면.","JPN":"ですが今回の分岐点すらも結局は無意味な滅亡に繋がるとしたら。","ENG":"However, if this turning point still converges into meaningless destruction...","TWN":"但是如果這次分界點最終還是無意義的毀滅…"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"구태여 무가치한 실패를 반복할 이유가 없겠죠.","JPN":"あえて価値のない失敗を繰り返す理由はありません。","ENG":"Then there is no point in repeating a worthless failure.","TWN":"沒有必要重複毫無價值的失敗吧。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"따라서 지금까지 모든 히스토리를 아카이브. 인류를 대상으로 선별 프로세스를 수행.","JPN":"従って、今までのすべてのヒストリーをアーカイブ。人類を対象に選別プロセスを遂行。","ENG":"Thus, I have archived all historical data up to this point and initiated the mankind selection process.","TWN":"因此，至今為止所有歷史都已歸檔。針對人類進行篩選流程。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"선별된 인류를 보존 처리하여 이민선에 수납합니다.","JPN":"選別された人類を保存処理し、移民船に収納します。","ENG":"The selected humans will be preserved and stored within the Exodus Fleet.","TWN":"將精選的人類進行保存處理並收納到移民船中。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그 후, 코핀 오브 릴리스의 동력을 사용하여 프로토콜 CoW를 발동.","JPN":"その後、コフィン・オブ・リリスの動力を使用しプロトコルCoWを発動。","ENG":"Afterward, the Coffin of Lilith will activate Protocol: CoW using its power source.","TWN":"之後，莉莉絲之科芬將會啟動CoW協議，並以其作為動力源。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"세계선을 이동하여 모든 변수를 초기화. 최초부터 낙원 탐사 플랜을 다시 시작합니다.","JPN":"世界線を移動してすべての変数を初期化。最初から楽園探査プランを始めます。","ENG":"I will shift to a different worldline, reset all variables, and restart the paradise exploration plan from the beginning.","TWN":"我會轉移到另一條世界線，重置所有變數，從頭重新啟動樂園探索計畫。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"세계선 이동? 그런 게 가능하다고……?","JPN":"世界線を移動？　そんなことができるの……？","ENG":"Shifting worldlines? Is that even possible...?","TWN":"移動世界線？這種事情真的可以做到嗎？"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그야 당연합니다, 애꾸눈 인간.","JPN":"当然です、眼帯の人間。","ENG":"Of course, one-eyed human.","TWN":"那當然，獨眼龍。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"시공간 종료 프로토콜은 코핀의 설계 목적이자, 애초부터 함장의 플랜이었으니까요.","JPN":"時空間終了プロトコルはコフィンの設計目的であり、最初から艦長のプランでした。","ENG":"Spacetime abortion protocol is the very purpose of Coffin's design and Captain's original plan.","TWN":"時空終止協定是科芬的設計目的，也是艦長的計畫。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아까부터 느꼈지만…….","JPN":"先ほどから思ってはいたのですが……","ENG":"I've been meaning to say, but...","TWN":"我從剛才開始就一直覺得……"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 양철 깡통이 하는 짓은 처음부터 끝까지 전부 사장님을 흉내 내고 있는 것 같군요.","JPN":"このブリキ缶、徹底的に社長の真似をしているようですね。","ENG":"It feels like Junk Metal has been imitating you all along, Boss.","TWN":"這鐵罐從頭到尾都在模仿老闆的行為呢。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"프로토콜 CoW라…….","JPN":"プロトコルCoWか……","ENG":"Protocol: CoW...","TWN":"CoW協議開始實施……"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그건 이상하군, 아시모프.","JPN":"しかしそれはおかしくないか、アシモフ。","ENG":"But that's odd, Asimov.","TWN":"不過那很奇怪，阿西莫夫。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무리 네가 코핀 오브 릴리스의 모든 통제권을 가지고 있다고 하더라도.","JPN":"いかに君がコフィン・オブ・リリスのすべての統制権を持っているとしても。","ENG":"Even if you have full control over the Coffin of Lilith...","TWN":"即使你擁有莉莉絲之科芬的所有控制權。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자의 승인 없이 시공간 종료 프로토콜을 발동할 수 없을 텐데?","JPN":"最高管理者の承認なしでは時空間終了プロトコルを発動できないはずだ。","ENG":"You can't activate the spacetime abortion protocol without the Supreme Administrator's approval.","TWN":"沒有最高管理者的批准，也無法啟動時空終止協議吧？"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그건 간단한 문제입니다, 함장.","JPN":"簡単なことです、艦長。","ENG":"That's a simple matter, Captain.","TWN":"這是個簡單的問題，艦長。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"제 모든 선별 대상에서 가장 우선순위가 높은 존재는 바로 당신입니다.","JPN":"私のすべての選別対象の中でもっとも優先順位が高い存在はあなたです。","ENG":"The entity at the top of my selection list is none other than you.","TWN":"在我的選擇清單中，優先順序最高的就是你。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"관측자로서 당신의 능력은 낙원 탐색에 필수적이니까요.","JPN":"観測者であるあなたの能力は楽園探索に必須ですから。","ENG":"Your abilities as the observer are essential for the paradise exploration.","TWN":"你作為觀察者的能力，對於樂園探索至關重要。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"선별 대상이라고? 그럼, 설마……?","JPN":"選別対象？　では、まさか……？","ENG":"Selection list? Wait, don't tell me...","TWN":"選擇清單？等等，別告訴我……？"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"따라서 함장, 당신을 선별하여 그 두뇌를 적출.","JPN":"つきましては艦長、あなたを選別してその頭脳を摘出。","ENG":"Therefore, Captain, I will select you and extract your brain.","TWN":"所以，艦長，我將選擇你，並提取你的大腦。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"적출한 두뇌를 테라브레인으로 해석하여 전자화. 전뇌 상태의 프로그램으로 치환합니다.","JPN":"摘出した頭脳をテラブレインで解析し電子化。電脳状態のプログラムに置換します。","ENG":"Your brain will be processed and digitized as a Terrabrain, converting it into a program.","TWN":"你的大腦將被處理並數位化成為特拉大腦，轉換成程式。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그 뒤 최종 시퀸스를 통해, 제 인공지능과 함장의 두뇌를 동기화. 의식의 융합을 시도.","JPN":"その後最終シーケンスを通じ、私の人工知能と艦長の頭脳を同期化。意識の融合を開始。","ENG":"After that, I will synchronize your consciousness with my AI through the final sequence, attempting a fusion of our minds.","TWN":"之後，我將透過最終序列將你的頭腦與我的AI同步，嘗試融合我們的意識。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"만약 그 시도가 성공한다면, 저는 함장이 되고 함장은 제가 되겠죠.","JPN":"もしそれが成功すれば、私は艦長となり、艦長は私となるでしょう。","ENG":"If the attempt succeeds, I will become you, and you will become me.","TWN":"如果那個嘗試成功的話，我就會成為艦長，而艦長就會成為我。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"따라서 우리는 새로운 존재로 거듭나게 될 겁니다.","JPN":"私たちは新たな存在に生まれ変わるのです。","ENG":"Thus, we will be reborn as a new entity.","TWN":"因此，我們將重生為新的存在。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님, 제가 방금 뭘 들은 거죠……?","JPN":"社長、今私はいったい何を聞いたのでしょう……？","ENG":"Boss, did I just hear what I think I heard...?","TWN":"老闆，我剛剛聽到了什麼？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저 미친 깡통이 지금 사장님의 머리를 열고, 뇌를 꺼내겠다고 한 것 같은데요……?","JPN":"あの狂ったボロ缶、社長の頭を開けて、脳を取り出すと言ったようですが……？","ENG":"Did that crazy Junk Metal just say that she's going to open your head and pull out your brain...?","TWN":"那個瘋鐵罐好像剛才說要打開老闆的腦袋，把腦子拿出來？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"당황스럽지만… 아무래도 자네가 들은 그대로인 것 같군, 부사장.","JPN":"残念だが……どうやら君が聞いたとおりのようだね、副社長。","ENG":"It's alarming, but... yes, I believe you heard it right, Vice President.","TWN":"雖然有些驚訝……但看來你聽到的就是事實，副總。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 아시모프는 거짓말을 하지 않아.","JPN":"それにアシモフは嘘をつかない。","ENG":"And Asimov does not lie.","TWN":"而且阿西莫夫是不會說謊的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"목표가 설정되면, 그것을 달성하기 위해 수단과 방법을 가리지 않겠지.","JPN":"目標が設定されれば、達成するために手段を選ばないだろう。","ENG":"Once she sets her goal, she will stop at nothing to achieve it.","TWN":"一旦設定目標，就會不擇手段地去達成吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"물론입니다, 함장.","JPN":"もちろんです、艦長。","ENG":"Indeed, Captain.","TWN":"當然了，艦長。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"당신과 작별한 뒤, 저는 오랜 시간 탐사를 이어오며, 오직 당신만을 생각해 왔습니다.","JPN":"あなたと別れてから、私は長い間探査しながらあなただけを思ってきました。","ENG":"Since we parted ways, I have been thinking only of you while exploring for eons.","TWN":"與你告別後，我在漫長的探索中一直只想著你。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"메모리에 저장된 당신의 말을 되뇌며, 의도를 추정하기 위해 연산능력을 할애해 왔죠.","JPN":"メモリーに記録されたあなたの言葉を繰り返し、意図を推定するために演算能力を使いました。","ENG":"I replayed your words stored in my memory, dedicating my processing power to decipher your intentions.","TWN":"我一直在回憶存儲在記憶中的你的話，並分配計算能力來推測你的意圖。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"줄곧 당신이라는 존재를 이해하기 위해 노력해왔습니다.","JPN":"ずっとあなたという存在を理解しようと努力し続けてきました。","ENG":"I have been striving to understand you.","TWN":"我一直在努力理解你這個存在。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"왜냐하면 당신이란 존재는 모든 세계를 통틀어, 제가 이해할 수 없는 유일한 미지니까요.","JPN":"なぜなら、あなたという存在は全世界でただひとつ、私が理解できない未知の存在だからです。","ENG":"Because you are the only unknown that I could not comprehend across all worlds.","TWN":"因為在所有世界中，唯有你是我無法理解的未知。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"상대를 이해하기 위해 노력하는 것. 상대와 계속 함께 있고 싶다고 느끼는 것.","JPN":"相手を理解しようと努力すること。相手と永遠に共にいたいと思うこと。","ENG":"Trying to understand someone... Wanting to stay with them forever...","TWN":"努力去理解對方。感受到想要一直和對方在一起。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"단점. 그리고 장점…. 상대의 모든 것을 받아들이는 것…….","JPN":"短所、そして長所……相手のすべてを受け入れること……","ENG":"Flaws. And strengths... Accepting everything...","TWN":"缺點，還有優點……接受對方的一切……"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"인간의 개념을 빌리자면, 그것은 <color=#ffd34c>사랑</color>이라고 해석됩니다.","JPN":"人間の概念を借りるなら、それは<color=#ffd34c>愛</color>と解釈できます。","ENG":"If I borrow the human concept, that is defined as <color=#ffd34c>love</color>.","TWN":"用人類的概念，那可以解釋為<color=#ffd34c>愛</color>。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그렇다면 저는 틀림없이 당신을 사랑하고 있는 것이겠죠.","JPN":"それなら私は間違いなく、あなたを愛しているのでしょう。","ENG":"Therefore, I must love you, Captain.","TWN":"那麼我一定是愛上你了吧。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사랑……!?","JPN":"愛……！？","ENG":"Love...?!","TWN":"愛！？"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"따라서 제가 내린 결론은 하나입니다.","JPN":"したがって、私はひとつの結論を出しました。","ENG":"Therefore, there is one conclusion I have reached.","TWN":"因此，我得出了一個結論。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L38_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"당신과 영원한 동기화를 희망합니다.","JPN":"あなたとの永遠なる同期化を希望します。","ENG":"I desire eternal synchronization with you.","TWN":"希望與你永遠同步。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"……함장.","JPN":"……艦長。","ENG":"...Captain.","TWN":"……艦長。"},"stage":{"bg":"MS_1403","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……축하드립니다, 사장님.","JPN":"……おめでとうございます、社長。","ENG":"...Congratulations, Boss.","TWN":"……恭喜你，老闆。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이제는 하다 하다 깡통을 뒤집어쓴 인공지능에게까지 프러포즈를 받는 데 성공하셨군요.","JPN":"ついにボロ缶を被っている人工知能にまでプロポーズされるに至ったのですね。","ENG":"You've somehow even managed to get a tin can AI to propose to you.","TWN":"現在搭載鐵桶的人工智慧都向你求婚了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"축의금은 넉넉하게 보내드리겠습니다. 회사 명의로 말이죠.","JPN":"ご祝儀はたくさんお送りします。会社名義で。","ENG":"I'll make sure to send you a generous wedding gift. Courtesy of the company.","TWN":"我會送上賀禮。當然是以公司的名義。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물론, 뇌를 적출당해, 깡통이 되어버린 사장님을 그대로 사장님으로 모실 수 있을지는…….","JPN":"もちろん、脳を摘出されてボロ缶になってしまった社長をそのまま社長として待遇していいかどうかは……","ENG":"Of course, whether we can still call you Boss after you become a tin can yourself, without a brain, is–","TWN":"不過是否能繼續把被摘除大腦變成空殼的老闆當作老闆來效勞……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니, 실언이었군요.","JPN":"いいえ、失言でした。","ENG":"Ah, I misspoke.","TWN":"不好意思，是我失言了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어차피 대외적으로는 지금도 그 망할 머신 갑으로 활동하고 계시죠?","JPN":"どうせ対外的には今もあのクソマシーン-甲-で活動していらっしゃいましたね。","ENG":"Aren't you still using that stupid Machine G.A.P. for the public anyway?","TWN":"反正現在對外也是以那個該死的機械·我超帥的形象在活動吧？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼, 아무런 문제가 없겠군요. 부디, 예쁜 사랑 하시길.","JPN":"では、何の問題もありません。どうか、お幸せに。","ENG":"In that case, there's no problem at all. I wish you a very happy love life.","TWN":"那麼，就沒有任何問題了。祝願你們擁有美好的愛情。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"문제가 없다니… 그게 무슨 섭섭한 소리인가?","JPN":"問題ないとは……悲しいことを言わないでくれ。","ENG":"No problem...? That's a bit disappointing.","TWN":"沒問題嗎？？那還真讓人失望。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보시다시피, 나는 틀림없는 사람일세. 문제가 아주 많아.","JPN":"見てのとおり、私は間違いなく人間だ。問題ありまくりだ。","ENG":"As you can see, I'm undeniably human. I have plenty of problems.","TWN":"正如你所見，我無可否認是個人類，問題多得很。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇군요. 요즘은 사람이 깡통을 자식으로 두기도 하는 모양이로군요.","JPN":"そうですか。最近は人間にボロ缶の子どもがいたりもするようですからね。","ENG":"Right. I suppose these days, even humans can have tin cans as children.","TWN":"沒錯，現在連人類也可能有鐵罐當孩子了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하나만으로도 골치 아파 죽겠는데, 그것도 <color=#ffd34c>둘</color>씩이나 말이죠.","JPN":"1人でも手に余っているのに、<color=#ffd34c>2人</color>も。","ENG":"Having just one was already a headache, but now there are <color=#ffd34c>two</color>?","TWN":"本來有一個就頭痛不已，現在竟然有<color=#ffd34c>兩個</color>？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정확히 말하면, 둘은 아니네만…….","JPN":"正確に言うと、2人ではないのだが……","ENG":"Strictly speaking, it's not exactly two...","TWN":"嚴格說起來，也不完全是兩個……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"방금 뭐라고 하셨죠?","JPN":"今何と？","ENG":"What was that?","TWN":"那是什麼？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 그나저나 이거 곤란하게 됐군.","JPN":"ゴホン、それより困ったな。","ENG":"Ahem, in any case, this is quite the predicament.","TWN":"嗯，總之，這確實是個難題。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아시모프가 내린 시험을 통과하지 못하면, 꼼짝없이 프러포즈를 받게 생겼으니까.","JPN":"アシモフの試験を乗り越えられないと、プロポーズを受け入れざるを得なくなる。","ENG":"If I don't pass Asimov's trial, I'll end up receiving that proposal after all.","TWN":"如果我沒通過阿西莫夫的試煉，最後還是會被逼著接受那個提案。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"깡통 주제에 제법 로맨틱한 표현을 쓰긴 했지만, 사실상 전 인류의 목숨을 건 협박입니다.","JPN":"ボロ缶のくせになかなかロマンチックな表現を使いましたが、実際、あれは全人類の命をかけた脅迫ですからね。","ENG":"Junk Metal may have used romantic words, but it was basically a threat against all of humanity.","TWN":"鐵罐或許說得浪漫，但本質上就是對全人類的威脅。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우선은 그 시험인가 뭔가를 해결할 수밖에 없겠군요.","JPN":"まずはその試験だか何だかを解決するしかありません。","ENG":"For now, I suppose we have no choice but to deal with this so-called trial.","TWN":"眼下，我想我們只能硬著頭皮應付這所謂的試煉了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇다면 미나 양에게 연락을…….","JPN":"ではミナさんに連絡を……","ENG":"In that case, I should contact Mina...","TWN":"那麼聯絡米娜……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"발신자 제한이라고……?","JPN":"発信者番号非通知……？","ENG":"An unknown number...?","TWN":"不明來電……？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"안녕, 수연아? 잘 지냈어?","JPN":"やあ、キズナ。元気だった？","ENG":"Hello, Sooyeon. How have you been?","TWN":"你好，秀妍。你最近怎麼樣？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임 이후로 처음인가? 다친 데는 괜찮고?","JPN":"クリフォトゲーム以来初めてかな？　怪我の具合はどう？","ENG":"Is this the first time since the Qliphoth Game? Are your injuries healing well?","TWN":"這是自逆卡巴拉遊戲後第一次聯絡嗎？傷勢恢復得還好嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"나, 나유빈……?","JPN":"い、イチノセ……？","ENG":"N-Na Yubin...?","TWN":"羅，羅瑜斌……？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네가 왜……?","JPN":"どうしてあなたが……？","ENG":"Why are you...?","TWN":"你怎麼會……？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 오래간만입니다.","JPN":"それから、お久しぶりです。","ENG":"And it's been a while, too.","TWN":"也好久不見了。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"때마침 곤란한 일을 겪고 계실 것 같아서, 무례를 무릅쓰고 먼저 연락드렸습니다.","JPN":"ちょうどお困りだろうと思って、無礼を承知で連絡さしあげました。","ENG":"I figured you'd be in some trouble, so I took the liberty of contacting you first.","TWN":"我覺得你可能遇到麻煩了，所以先主動聯絡了你。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……관리자님.","JPN":"……管理者さん。","ENG":"...Administrator.","TWN":"……管理者。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"相同一時間"},"stage":{"bg":"BLACK","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 ~ 로터스 관리 경계 구역","JPN":"シャレード～ロータス管理警戒区域","ENG":"Charade-Lotus Perimeter Zone","TWN":"查雷德～洛德斯管理警戒區域"},"stage":{"bg":"BLACK","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"조금만 기다려, 노엘.","JPN":"あと少しだけ待ってて、ノエル。","ENG":"Just hold on a little longer, Noelle.","TWN":"稍等一下，洛艾兒。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 반드시 구하러 갈 테니까…….","JPN":"私が必ず助けに行くから……","ENG":"I will save you...","TWN":"我一定會去救你的……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_QM","text":{"KOREA":"이야~ 이제야 도착한 거야?","JPN":"いや～やっと着いたの？","ENG":"Well, well. Look who finally got here.","TWN":"哇～現在才到嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_QM","text":{"KOREA":"조금만 더 빨리 오지 그랬어? 기다리느라 심심해서 죽는 줄 알았다니깐~?","JPN":"もうちょっと早く来てくれればよかったのに。待ってる間暇で暇で～","ENG":"Couldn't you have shown up a bit sooner? I was bored out of my mind waiting!","TWN":"怎麼不早點來呢？等得我都快無聊死了～"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너는……?","JPN":"あなた……？","ENG":"You're...?","TWN":"你是……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 네가 왜 여기에 있어……?","JPN":"ちょっと、なんであなたがここに……？","ENG":"Wait, what are you doing here...?","TWN":"等一下，你為什麼？在這裡……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하아… 예상하긴 했지만 이거 섭섭하네.","JPN":"はあ……予想はしてたけど、寂しいもんね。","ENG":"*Sigh...* I kinda expected this, but still, it stings.","TWN":"哈……雖然我預料到了，但還是有點失望啊。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"설마, 그 실눈 녀석이랑 너희 소대장… 둘 다 나에 대해서 아무 말도 안 해준 거야?","JPN":"まさか、あの糸目とあんたの小隊長……2人ともあたしについて言ってくれなかったわけ？","ENG":"So neither your commander nor the squinty one... told you a single thing about me?","TWN":"難道，那位眯眯眼和你們的小隊長……都沒有告訴你們關於我的事情嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에이미……?","JPN":"エイミー……？","ENG":"Amy...?","TWN":"艾米……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너, 정말로 에이미 맞아……?","JPN":"あなた、本当にエイミーなの……？","ENG":"Are you... really Amy...?","TWN":"你，真的是艾米嗎？？？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 에이미는 그때 분명히……?","JPN":"でも、エイミーはあの時確か……","ENG":"But I saw you got...","TWN":"但是艾米那天明明……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아하하. 이런저런 사정이 있어서 말이지.","JPN":"あはは、色々あってね。","ENG":"Ahaha, yeah. Let's just say... it's complicated.","TWN":"啊哈哈，因為各種原因啦。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L48_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐, 재미없는 걸즈 토크 같은 건, 나중에 천천히 하자고.","JPN":"ま、つまんないガールズトークは後でゆっくりしようよ。","ENG":"Anyway, we can save the boring chatter for later.","TWN":"這種女生之間的閒聊，之後再慢慢聊吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"지금은 그런 것보다 더 중요한 일이 있잖아?","JPN":"今はそんなことより大事なことがあるんでしょ？","ENG":"There's something way more important on the table right now.","TWN":"現在有比這個更重要的事吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"중요한 일이라고?","JPN":"大事なこと？","ENG":"More important?","TWN":"重要的事情？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"망할 년 하나를 찾고 있거든.","JPN":"くそ女を1人探してるの。","ENG":"I'm tracking down someone, damn it.","TWN":"我在找一個該死的女人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"위치는 대충 알아냈는데, 네 협조가 필요해서 말이야.","JPN":"場所はだいたい掴んだけど、あんたの協力が必要でさ。","ENG":"I've more or less pinned down her location, and just need your help to get to her.","TWN":"大致知道位置了，但需要你的協助。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"……유미나.","JPN":"……ヤナギ・ミナ。","ENG":"...Yoo Mina.","TWN":"……劉米娜。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양. 제 말이 들리나요?","JPN":"ミナさん、聞こえますか？","ENG":"Mina. Can you hear me?","TWN":"米娜，聽得到我說話嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부사장님?","JPN":"副社長？","ENG":"Vice President?","TWN":"副總？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"바루나 투어를 통해 연락 받았습니다. 차원 폭풍에 휘말렸다면서요?","JPN":"ヴァルナツアーから連絡を受けました。次元の暴風に巻き込まれたそうですね。","ENG":"I received your message through Varuna Tour. You said you were caught in a dimensional storm?","TWN":"我透過瓦魯納之旅收到了你的訊息。你說你被困在次元風暴中了？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맞아. 수리야가 활약해 준 덕분에 거기서 탈출할 수 있었어.","JPN":"そうなんだ。スーリヤのおかげでそこから脱出できたんだよ。","ENG":"Yeah. Thanks to Surya, I managed to escape.","TWN":"是的，多虧了蘇莉耶，我才得以逃脫。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서 가이드들은? 무사한 거 맞지?","JPN":"それで、ガイドたちは？　無事だよね？","ENG":"What about the guides? Are they safe?","TWN":"那些導遊呢？她們安全嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"두 사람이라면 걱정하지 않아도 괜찮습니다. 무사히 탈출했다고 전달받았으니까요.","JPN":"お二人なら心配しなくても大丈夫です。無事脱出したと聞きましたので。","ENG":"You don't need to worry about them. I was told they escaped safely.","TWN":"你不用擔心她們，據說她們都安全逃出了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그보다 미나 양에게 전할 말이 있습니다.","JPN":"それより、ミナさんにお話があります。","ENG":"But more importantly, I have something to tell you.","TWN":"但更重要的是，我有事要告訴你。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"전할 말이라고?","JPN":"話？","ENG":"Something to tell me?","TWN":"有事要告訴我？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어이, 아줌마. 오랜만이야? 잘 지냈어?","JPN":"やっほー、おばさん。久しぶり。元気してた？","ENG":"Hey. It's been a while. How have you been?","TWN":"嘿，好久不見了。你最近過得如何？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……벌써 만나버렸군요. 그럼, 어쩔 수 없겠네요.","JPN":"……もう会ってしまいましたか。では、仕方ありませんね。","ENG":"...So, you've already met. Well, it can't be helped then.","TWN":"……所以，你們已經見過面了。那也沒辦法了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"벌써 만나다니, 그게 무슨 소리야? 부사장님은 에이미를 어떻게 알고 있는 건데?","JPN":"もう会ってしまったって、どういうこと？　副社長はエイミーのこと、なんで知ってるの？","ENG":"Already met? What do you mean? How do you know Amy?","TWN":"已經見過面？什麼意思？你怎麼認識艾米？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양, 진정하고 잘 들으세요.","JPN":"ミナさん、落ち着いてよく聞いてください。","ENG":"Mina, calm down and listen carefully.","TWN":"米娜，冷靜點，仔細聽我說。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"거기 있는 에이미 퍼스트윙은 육익의 일원입니다.","JPN":"そこにいるエイミー・ファーストウイングは六翼の一員です。","ENG":"That is Amy Firstwing, a member of Six Wings.","TWN":"那是艾米·弗斯特薇六翼成員之一。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"퍼스트윙? 아니… 그보다 육익이라고……?","JPN":"ファーストウイング？　いや、待って。六翼……？","ENG":"Firstwing? Wait... Six Wings...?","TWN":"弗斯特薇？等等……六翼……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 나유빈의 동료라는 뜻이잖아!","JPN":"それって、イチノセ・カオルの仲間ってことじゃん！","ENG":"That means she's with Na Yubin!","TWN":"那表示她跟羅瑜斌是一夥的！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇습니다, 미나 양.","JPN":"そのとおりです、ミナさん。","ENG":"That's correct, Mina.","TWN":"沒錯，米娜。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 지금은 서로의 이익을 위한, 일시적 동맹 관계…….","JPN":"そして今はお互いの利益のための、一時的な同盟関係……","ENG":"And right now, we have a temporary alliance with her to mutually benefit...","TWN":"而且目前我們和她暫時結盟，達成互利……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다시 말해, <color=#ffd34c>조력자</color>라고도 할 수 있겠군요.","JPN":"つまり、<color=#ffd34c>協力者</color>とも言えるでしょう。","ENG":"In other words, you could say she's a <color=#ffd34c>supporter</color>.","TWN":"換句話說，你可以說她是個<color=#ffd34c>幫手</color>。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"조력자……?","JPN":"協力者……？","ENG":"Supporter...?","TWN":"幫手……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};